// components/ChatbotInterface.jsx - COMPLETE FIXED VERSION
import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import './ERPChatBot.css';

const ChatbotInterface = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId, setSessionId] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [isCheckingAuth, setIsCheckingAuth] = useState(true);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Initialize on component mount
  useEffect(() => {
    loadUserInfo();
    loadSavedMessages();
    
    // Auto-open if there are unread messages
    const saved = localStorage.getItem('chatbot_messages');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.length > 0) {
        const lastMsg = parsed[parsed.length - 1];
        if (lastMsg.sender === 'bot') {
          setIsOpen(true);
        }
      }
    }
  }, []);

  // Auto-scroll to bottom
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Save messages
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('chatbot_messages', JSON.stringify(messages));
    }
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // ✅ FIXED: Load user info from session
  const loadUserInfo = async () => {
    try {
      setIsCheckingAuth(true);
      const response = await axios.get('/api/auth/me', {
        withCredentials: true
      });
      
      console.log('Auth response:', response.data); // Debug log
      
      if (response.data && response.data.user) {
        const userData = response.data.user;
        setUserInfo({
          id: userData._id,
          role: userData.role,
          studentId: userData.studentId || userData.username || 'unknown',
          email: userData.email || userData.universityEmail,
          name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
          firstName: userData.firstName
        });
        
        // Store in localStorage for persistence
        localStorage.setItem('userInfo', JSON.stringify(userData));
      }
    } catch (error) {
      console.log('Auth check failed, using localStorage:', error.message);
      
      // Fallback to localStorage if session fails
      const stored = localStorage.getItem('userInfo');
      if (stored) {
        const userData = JSON.parse(stored);
        setUserInfo({
          id: userData._id,
          role: userData.role,
          studentId: userData.studentId || userData.username,
          email: userData.email || userData.universityEmail,
          name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
          firstName: userData.firstName
        });
      }
    } finally {
      setIsCheckingAuth(false);
    }
  };

  const loadSavedMessages = () => {
    const saved = localStorage.getItem('chatbot_messages');
    if (saved) {
      try {
        setMessages(JSON.parse(saved));
      } catch (e) {
        console.error('Error loading saved messages:', e);
      }
    }
  };

  // ✅ FIXED: Handle send message with proper authentication
  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!inputMessage.trim() || isLoading) return;

    const userMessage = inputMessage.trim();
    setInputMessage('');
    
    // Add user message to chat
    const newUserMessage = {
      id: Date.now(),
      text: userMessage,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages(prev => [...prev, newUserMessage]);
    setIsLoading(true);

    try {
      // ✅ FIXED: Send with credentials
      const response = await axios.post('/api/chatbot/chat', {
        message: userMessage,
        sessionId: sessionId
      }, {
        withCredentials: true,
        headers: {
          'Content-Type': 'application/json'
        }
      });

      console.log('Chat response:', response.data); // Debug log

      if (response.data.success) {
        if (response.data.sessionId) {
          setSessionId(response.data.sessionId);
          localStorage.setItem('chatbotSessionId', response.data.sessionId);
        }

        const botMessage = {
          id: Date.now() + 1,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          metadata: response.data.metadata
        };
        
        setMessages(prev => [...prev, botMessage]);
      } else {
        addErrorMessage(response.data.message || "Something went wrong");
      }
    } catch (error) {
      console.error('Chat error:', error);
      
      // Handle specific error cases
      let errorText = "Sorry, I'm having trouble connecting. Please try again.";
      
      if (error.response) {
        switch (error.response.status) {
          case 401:
            errorText = "Session expired. Please refresh the page and log in again.";
            setUserInfo(null);
            break;
          case 403:
            errorText = "You don't have permission to use the chatbot.";
            break;
          case 500:
            errorText = "Server error. Please try again later.";
            break;
          default:
            errorText = error.response.data?.message || "Something went wrong.";
        }
      } else if (error.request) {
        errorText = "No response from server. Check your internet connection.";
      }
      
      addErrorMessage(errorText);
    } finally {
      setIsLoading(false);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  const addErrorMessage = (text) => {
    const errorMessage = {
      id: Date.now() + 1,
      text: text,
      sender: 'system',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      isError: true
    };
    setMessages(prev => [...prev, errorMessage]);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage(e);
    }
  };

  const handleClearChat = () => {
    if (window.confirm('Clear all chat history?')) {
      setMessages([]);
      localStorage.removeItem('chatbot_messages');
      setSessionId(null);
      localStorage.removeItem('chatbotSessionId');
    }
  };

  const handleQuickAction = (text) => {
    setInputMessage(text);
    setTimeout(() => {
      if (inputRef.current) {
        inputRef.current.focus();
      }
    }, 100);
  };

  const refreshUserInfo = async () => {
    await loadUserInfo();
    addSystemMessage("User info refreshed. You can now ask questions.");
  };

  const addSystemMessage = (text) => {
    const systemMessage = {
      id: Date.now(),
      text: text,
      sender: 'system',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setMessages(prev => [...prev, systemMessage]);
  };

  const quickActions = [
    { text: "What's my fee due?", icon: "💰" },
    { text: "Show today's timetable", icon: "📅" },
    { text: "My attendance in CS101", icon: "📊" },
    { text: "Upcoming events", icon: "🎉" },
    { text: "Show my results", icon: "📝" },
    { text: "What courses do I have?", icon: "📚" }
  ];

  // Show loading while checking auth
  if (isCheckingAuth) {
    return (
      <button 
        className="chatbot-icon"
        style={{ background: '#6b7280' }}
        onClick={() => setIsOpen(true)}
      >
        <div className="spinner-small"></div>
      </button>
    );
  }

  const isLoggedIn = !!userInfo;

  return (
    <>
      {/* Chatbot Icon */}
      {!isOpen && (
        <button 
          className="chatbot-icon"
          onClick={() => setIsOpen(true)}
          aria-label="Open chatbot"
          style={{ 
            background: isLoggedIn ? 
              'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' : 
              '#9ca3af' 
          }}
        >
          <div className="chatbot-icon-inner">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
              <path d="M12 2C6.48 2 2 6.48 2 12C2 17.52 6.48 22 12 22C17.52 22 22 17.52 22 12C22 6.48 17.52 2 12 2ZM12 20C7.59 20 4 16.41 4 12C4 7.59 7.59 4 12 4C16.41 4 20 7.59 20 12C20 16.41 16.41 20 12 20Z" fill="white"/>
              <path d="M11 11H13V17H11V11ZM11 7H13V9H11V7Z" fill="white"/>
            </svg>
            <span className="chatbot-icon-badge">
              {isLoggedIn ? "💬" : "🔒"}
            </span>
          </div>
        </button>
      )}

      {/* Chatbot Window */}
      {isOpen && (
        <div className="chatbot-window">
          {/* Header */}
          <div className="chatbot-header">
            <div className="chatbot-header-content">
              <div className="chatbot-avatar">
                <span>🤖</span>
              </div>
              <div className="chatbot-header-text">
                <h3>ERP Assistant</h3>
                <p className="chatbot-status">
                  <span className={`status-dot ${isLoggedIn ? 'online' : 'offline'}`}></span>
                  {isLoading ? 'Typing...' : isLoggedIn ? 'Online' : 'Offline'}
                  {isLoggedIn && userInfo.studentId && (
                    <span className="chatbot-user-id"> • {userInfo.studentId}</span>
                  )}
                </p>
              </div>
            </div>
            <div className="chatbot-header-actions">
              {!isLoggedIn && (
                <button 
                  className="refresh-btn"
                  onClick={refreshUserInfo}
                  title="Refresh login status"
                >
                  ↻
                </button>
              )}
              <button 
                className="chatbot-close-btn"
                onClick={() => setIsOpen(false)}
                aria-label="Close chatbot"
              >
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                  <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor"/>
                </svg>
              </button>
            </div>
          </div>

          {/* Messages Container */}
          <div className="chatbot-messages">
            {messages.length === 0 ? (
              <div className="chatbot-welcome">
                <div className="welcome-avatar">
                  <span>🤖</span>
                </div>
                <h3>Hello{isLoggedIn && userInfo.firstName ? ` ${userInfo.firstName}` : ''}!</h3>
                <p>I'm your ERP Assistant. I can help you with:</p>
                
                <div className="quick-actions">
                  <div className="quick-actions-grid">
                    {quickActions.map((action, index) => (
                      <button
                        key={index}
                        className={`quick-action-btn ${!isLoggedIn ? 'disabled' : ''}`}
                        onClick={() => isLoggedIn ? handleQuickAction(action.text) : null}
                        disabled={!isLoggedIn}
                        title={!isLoggedIn ? "Please login first" : action.text}
                      >
                        <span className="quick-action-icon">{action.icon}</span>
                        <span className="quick-action-text">{action.text}</span>
                      </button>
                    ))}
                  </div>
                  
                  {!isLoggedIn && (
                    <div className="login-prompt">
                      <div className="login-icon">🔒</div>
                      <p>You need to be logged in to ask questions about your data.</p>
                      <div className="login-actions">
                        <button 
                          className="login-btn"
                          onClick={() => window.location.href = '/login'}
                        >
                          Go to Login
                        </button>
                        <button 
                          className="refresh-btn-small"
                          onClick={refreshUserInfo}
                        >
                          Refresh Status
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              messages.map((message) => (
                <div
                  key={message.id}
                  className={`message ${message.sender} ${message.isError ? 'error' : ''}`}
                >
                  {message.sender === 'bot' && (
                    <div className="message-avatar">🤖</div>
                  )}
                  {message.sender === 'system' && (
                    <div className="message-avatar">ℹ️</div>
                  )}
                  <div className="message-content">
                    <div className="message-text">
                      {message.text.split('\n').map((line, i) => (
                        <React.Fragment key={i}>
                          {line}
                          {i < message.text.split('\n').length - 1 && <br />}
                        </React.Fragment>
                      ))}
                    </div>
                    <div className="message-timestamp">
                      {message.timestamp}
                      {message.metadata?.intent && (
                        <span className="message-intent">
                          • {message.metadata.intent}
                        </span>
                      )}
                    </div>
                  </div>
                  {message.sender === 'user' && (
                    <div className="message-avatar user-avatar">👤</div>
                  )}
                </div>
              ))
            )}
            
            {isLoading && (
              <div className="message bot">
                <div className="message-avatar">🤖</div>
                <div className="message-content">
                  <div className="typing-indicator">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                </div>
              </div>
            )}
            
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <form className="chatbot-input-area" onSubmit={handleSendMessage}>
            <div className="input-wrapper">
              <textarea
                ref={inputRef}
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={isLoggedIn ? "Ask about fees, attendance, timetable..." : "Please log in to ask questions"}
                rows="1"
                disabled={isLoading || !isLoggedIn}
                autoFocus={isLoggedIn}
              />
              <button 
                type="submit" 
                className="send-btn"
                disabled={!inputMessage.trim() || isLoading || !isLoggedIn}
                title={!isLoggedIn ? "Please login first" : "Send message"}
              >
                {isLoading ? (
                  <div className="spinner"></div>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                    <path d="M2.01 21L23 12L2.01 3L2 10L17 12L2 14L2.01 21Z" fill="currentColor"/>
                  </svg>
                )}
              </button>
            </div>
            
            <div className="chatbot-footer">
              <button 
                type="button" 
                className="footer-btn"
                onClick={handleClearChat}
                title="Clear chat history"
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                  <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor"/>
                </svg>
                Clear
              </button>
              
              <div className="user-info">
                {isLoggedIn ? (
                  <>
                    <span className="user-role">{userInfo.role}</span>
                    {userInfo.studentId && (
                      <span className="user-id">{userInfo.studentId}</span>
                    )}
                    <button 
                      className="refresh-btn-tiny"
                      onClick={refreshUserInfo}
                      title="Refresh user info"
                    >
                      ↻
                    </button>
                  </>
                ) : (
                  <>
                    <span className="user-not-logged">Not logged in</span>
                    <button 
                      className="refresh-btn-tiny"
                      onClick={refreshUserInfo}
                      title="Check login status"
                    >
                      ↻
                    </button>
                  </>
                )}
              </div>
              
              <div className="hint-text">
                {isLoggedIn ? "Press Enter to send • Shift+Enter for new line" : "Login required to chat"}
              </div>
            </div>
          </form>
        </div>
      )}
    </>
  );
};

export default ChatbotInterface;
